```
// Get the canvas element
var ctx = document.getElementById('myChart').getContext('2d');

// Set the data
var data = {
  labels: ['January', 'February', 'March', 'April', 'May'],
  datasets: [{
    label: 'Data',
    data: [20, 15, 10, 25, 30],
    backgroundColor: [
      '#FF6384',
      '#63FF84',
      '#84FF63',
      '#8463FF',
      '#6384FF'
    ]
  }]
};

// Create the pie chart
var myPieChart = new Chart(ctx, {
  type: 'pie',
  data: data
});
```

